import{_ as a,o,c as t,ag as n}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"清朝政治制度：","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-16.md","filePath":"notes/note-16.md"}'),e={name:"notes/note-16.md"};function r(s,p,l,c,d,i){return o(),t("div",null,[...p[0]||(p[0]=[n('<h1 id="清朝政治制度" tabindex="-1">清朝政治制度： <a class="header-anchor" href="#清朝政治制度" aria-label="Permalink to &quot;清朝政治制度：&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、清朝政治制度：</span></p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">①康熙：</span>南书房；</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">②雍正：</span>军机处，便于皇帝独掌朝政，君主专制进一步强化，君主专制达到顶峰。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、清朝前期人口增长的原因：</span></p><p>①统治者采取恢复社会经济的措施，使经济发展，社会安定。</p><p>②推广玉米、甘薯等高产作物。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、明朝经济发展的表现：</span>农业：引进玉米、甘薯、花生、向日葵等作物。（新航路开辟有关）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">手工业：</span>棉纺织业由南方推广到北方，出现棉纺织基地；苏州是明代丝织业中心；景德镇是制瓷中心，代表青花瓷。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">商业：</span>商品经济活跃；北京、南京是全国商贸城市；商帮：晋商、徽商。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、清朝前期经济发展的原因：</span></p><p>①国家统一、社会安定；</p><p>②清初统治者重视农业生产，大力推行垦荒政策；</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、表现：</span></p><p>①耕地面积扩大；</p><p>②兴修水利；</p><p>③推广玉米、甘薯等高产作物（与新航路开辟有关！）；</p><p>④经济作物品种增多（重点关注烟草，与新航路开辟有关！）。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、清朝前期经济发展的影响：</span></p><p>①有利于社会稳定与繁荣；</p><p>②为清朝前期的兴盛奠基；</p><p>③推动手工业和城镇商品经济的发展。</p>',22)])])}const _=a(e,[["render",r]]);export{v as __pageData,_ as default};
